mapper.update:
update coupon
name = #{name}, coupon_type = #{couponType}, publish_type = #{publishType}, store_id = #{storeId}, receive_type = #{receiveType}, threshold_amount = #{thresholdAmount}, discount_amount = #{discountAmount}, discount_rate = #{discountRate}, total_count = #{totalCount}, per_user_limit = #{perUserLimit}, start_time = #{startTime}, end_time = #{endTime}, status = #{status}, remark = #{remark}, update_user = #{updateUser}, update_time = #{updateTime}
where id = #{id}

mapper.select:
select c.*, s.name as store_name
from coupon c
         left join store s on c.store_id = s.id


        and c.name like concat('%', #{name}, '%')


        and c.coupon_type = #{couponType}


        and c.status = #{status}


        and c.publish_type = #{publishType}


        and c.store_id = #{storeId}


order by c.id desc
